mapper.select:
SELECT PCCT.CONT_NUM , PCCT.CONT_CNT , PCCT.CONT_NUM ' / ' PCCT.CONT_CNT AS CONT_NUM_AND_CNT , PCCT.BUYER_CD ,GETCOMPANYNAME(PCCT.GATE_CD, PCCT.BUYER_CD, #{ses.langCd}) AS BUYER_NM , PCCT.CONT_USER_ID ,getUserName(PCCT.GATE_CD, PCCT.CONT_USER_ID, #{ses.langCd}) AS CONT_USER_NM , PCCT.CONT_DESC , PCCT.CONT_REMARK , PCCT.ATT_FILE_NUM , PCCT.SIGN_STATUS , PCCT.APP_DOC_NUM , PCCT.APP_DOC_CNT FROM STOCPCCT PCCT WHERE PCCT.GATE_CD = #{ses.gateCd} AND PCCT.BUYER_CD = #{BUYER_CD}
AND PCCT.CONT_NUM = #{CONT_NUM} AND PCCT.CONT_CNT = #{CONT_CNT}
AND PCCT.APP_DOC_NUM = #{APP_DOC_NUM}
AND PCCT.DEL_FLAG = '0'

SELECT SIGN_STATUS
  FROM STOCPCCT
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND DEL_FLAG = '0'

mapper.insert:
        INSERT INTO STOCPCCT (
              GATE_CD
			, BUYER_CD
			, CONT_NUM
			, CONT_CNT
			, REG_DATE
			, REG_USER_ID
			, MOD_DATE
			, MOD_USER_ID
			, DEL_FLAG
			, CONT_USER_ID
			, CONT_DESC
			, CONT_REMARK
			, ATT_FILE_NUM
			, SIGN_STATUS
        )
        VALUES (
              #{ses.gateCd}
			, #{BUYER_CD}
			, #{CONT_NUM}
			, #{CONT_CNT}
			, SYSDATE
			, #{ses.userId}
			, SYSDATE
			, #{ses.userId}
			, '0'
			, #{CONT_USER_ID}
			, #{CONT_DESC}
			, #{CONT_REMARK}
			, #{ATT_FILE_NUM}
			, 'T' -- 작성중
    	)

