			, CONT_DESC    = #{CONT_DESC}
			, CONT_REMARK  = #{CONT_REMARK}
			, ATT_FILE_NUM = #{ATT_FILE_NUM}
            , SIGN_STATUS  = 'T'
        WHERE GATE_CD  = #{ses.gateCd}
          AND BUYER_CD = #{BUYER_CD}
          AND CONT_NUM = #{CONT_NUM}
          AND CONT_CNT = #{CONT_CNT}
          AND DEL_FLAG = '0'

