UPDATE STOCPCCT SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , SIGN_STATUS = #{SIGN_STATUS}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}

        UPDATE STOCPCCT
		   SET APP_DOC_NUM = #{APP_DOC_NUM}
             , APP_DOC_CNT = CASE WHEN #{APP_DOC_CNT} = '' THEN NULL ELSE #{APP_DOC_CNT} END
         WHERE GATE_CD  = #{ses.gateCd}
           AND BUYER_CD = #{BUYER_CD}
           AND CONT_NUM = #{CONT_NUM}
           AND CONT_CNT = #{CONT_CNT}

mapper.select:
SELECT PCCT.CONT_NUM , PCCT.CONT_CNT , PCCT.BUYER_CD ,GETCUSTNAME(PCCT.GATE_CD, PCCT.BUYER_CD) AS BUYER_NM , PCCT.CONT_USER_ID ,GETUSERNAME(PCCT.GATE_CD, PCCT.CONT_USER_ID, #{ses.langCd}) AS CONT_USER_NM ,GETUSERNAME(PCCT.GATE_CD, PCCT.CONT_USER_ID, #{ses.langCd}) AS DEC_CONT_USER_NM -- 메일방송용 ,USERC.TEL_NUM AS DEC_CONT_TEL_NUM -- 메일발송용 , USERC.DEPT_CD , OGDP.DEPT_NM ,(PCCT.SIGN_DATE, 'yyyyMMdd') AS SEND_DATE , PCCT.CONT_DESC , PCCT.CONT_REMARK , PCWU.PROGRESS_CD , PCWU.WORKER_USER_ID AS WORKER_ID , PCWU.WORKER_USER_ID AS ENC_WORKER_ID ,GETUSERNAME(PCWU.GATE_CD, PCWU.WORKER_USER_ID, #{ses.langCd}) AS WORKER_NM ,USERD.EMAIL AS EMAIL ,USERD.TEL_NUM AS TEL_NUM ,USERD.CELL_NUM AS CELL_NUM , USERD.SITE_USER_ID ,GETUSERNAME(USERD.GATE_CD, USERD.SITE_USER_ID, #{ses.langCd}) AS SITE_USER_NM ,GETCODENAME(USERD.GATE_CD, 'M151', USERD.GENDER, #{ses.langCd}) AS GENDER ,USERC.ZIP_CD AS ZIP_CD ,USERD.ADDR_1 AS ADDR_1 ,USERD.ADDR_2 AS ADDR_2 ,(USERD.BIRTH_DATE, 'yyyyMMdd') AS BIRTH_DATE , PCWU.WORKER_DEPT_NM , PCWU.WORKER_JOB_NM ,(PCWU.WORKER_CONT_DATE, 'yyyyMMdd') AS WORKER_CONT_DATE ,(PCWU.WORKER_CONT_START_DATE, 'yyyyMMdd') AS WORKER_CONT_START_DATE ,(PCWU.WORKER_CONT_END_DATE, 'yyyyMMdd') AS WORKER_CONT_END_DATE , PCWU.BASE_PAY , PCWU.BASE_PAY_RMKS , PCWU.FOOD_PAY , PCWU.FOOD_PAY_RMKS , PCWU.JOB_PAY , PCWU.JOB_PAY_RMKS , PCWU.EXTEND_PAY , PCWU.EXTEND_PAY_RMKS , PCWU.WORK_PAY , PCWU.WORK_PAY_RMKS , PCWU.NIGHT_PAY , PCWU.NIGHT_PAY_RMKS , PCWU.ETC_PAY , PCWU.ETC_PAY_RMKS , PCWU.ETC_PAY2 , PCWU.ETC_PAY2_RMKS , PCWU.ETC_PAY3 , PCWU.ETC_PAY3_RMKS , PCWU.SPEC_RMKS , PCWU.WORKER_PAY_AMT , PCCT.ATT_FILE_NUM ,getFileCount(PCCT.GATE_CD, PCCT.ATT_FILE_NUM) AS ATT_FILE_CNT ,((PCWU.SIGN_DATE, 'YYYY-MM-DD HH24:MI'),' ') AS SIGN_DATE , PCWU.STOP_RMK , USERD.DEL_FLAG AS USER_DEL_FLAG , PCCT.SIGN_STATUS , PCWU.ATT_FILE_NUM AS PDF_ATT_FILE_NUM ,getFileCount(PCWU.GATE_CD, PCWU.ATT_FILE_NUM) AS PDF_ATT_FILE_CNT , PCWU.SEND_YN FROM STOCPCCT PCCT JOIN STOCPCWU PCWU ON (PCCT.GATE_CD = PCWU.GATE_CD AND PCCT.BUYER_CD = PCWU.BUYER_CD AND PCCT.CONT_NUM = PCWU.CONT_NUM AND PCCT.CONT_CNT = PCWU.CONT_CNT AND PCWU.DEL_FLAG = '0') LEFT OUTER JOIN STOCCVUR USERD ON (PCWU.GATE_CD = USERD.GATE_CD AND PCWU.WORKER_USER_ID = USERD.USER_ID AND USERD.DEL_FLAG = '0') LEFT OUTER JOIN STOCCVUR USERC ON (PCCT.GATE_CD = USERC.GATE_CD AND PCCT.CONT_USER_ID = USERC.USER_ID AND USERC.DEL_FLAG = '0') LEFT OUTER JOIN STOCOGDP OGDP ON (USERC.GATE_CD = OGDP.GATE_CD AND USERC.COMPANY_CD = OGDP.BUYER_CD AND USERC.DEPT_CD = OGDP.DEPT_CD AND OGDP.DEL_FLAG = '0') WHERE PCCT.GATE_CD = #{ses.gateCd} AND PCCT.BUYER_CD = #{BUYER_CD} AND PCCT.DEL_FLAG = '0'
AND (PCCT.CONT_USER_ID = #{CONT_USER_ID} -- 계약담당자 OR EXISTS ( SELECT 1 FROM STOCSCTP SCTP WHERE PCCT.GATE_CD = SCTP.GATE_CD AND PCCT.APP_DOC_NUM = SCTP.APP_DOC_NUM AND PCCT.APP_DOC_CNT = SCTP.APP_DOC_CNT AND SCTP.DEL_FLAG = '0' AND SCTP.SIGN_USER_ID = #{CONT_USER_ID} --결재자 ) )
AND PCCT.REG_DATE >= (#{REG_FROM_DATE}) AND PCCT.REG_DATE <= (#{REG_TO_DATE})
AND OGDP.DEPT_NM LIKE '%' #{DEPT_NM} '%'
AND PCCT.BUYER_CD = #{BUYER_CD}
AND UPPER(GETCOMPANYNAME(PCCT.GATE_CD, PCCT.BUYER_CD, #{ses.langCd})) LIKE '%' UPPER(#{BUYER_NM}) '%'
AND (PCCT.CONT_DESC LIKE '%' #{CONT_DESC} '%' OR PCCT.CONT_NUM LIKE '%' #{CONT_DESC} '%')
AND PCCT.CONT_USER_ID = #{CONT_USER_ID}
AND UPPER(GETUSERNAME(PCCT.GATE_CD, PCCT.CONT_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{CONT_USER_NM}) '%'
AND PCWU.PROGRESS_CD IN ${PROGRESS_CD}
AND PCWU.WORKER_USER_ID = #{WORKER_USER_ID}
AND UPPER(GETUSERNAME(PCWU.GATE_CD, PCWU.WORKER_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{WORKER_USER_NM}) '%'
AND PCWU.WORKER_DEPT_NM LIKE '%' #{WORKER_DEPT_NM} '%'
AND PCWU.WORKER_JOB_NM LIKE '%' #{WORKER_JOB_NM} '%'
AND PCCT.SIGN_STATUS IN ${SIGN_STATUS}
ORDER BY PCCT.CONT_NUM DESC , PCCT.CONT_CNT DESC , USERD.USER_NM

mapper.update:
UPDATE STOCPCWU
   SET MOD_DATE    = SYSDATE
     , MOD_USER_ID = #{ses.userId}
     , STOP_DATE   = SYSDATE
     , PROGRESS_CD = '300' -- 계약체결중단
     , STOP_RMK    = #{STOP_RMK}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND WORKER_USER_ID = #{WORKER_ID}

mapper.select:
SELECT PCCT.CONT_NUM , PCCT.BUYER_CD , PCCT.CONT_CNT , PCCT.CONT_DESC , PCWU.PROGRESS_CD , PCWU.WORKER_USER_ID AS WORKER_ID ,GETUSERNAME(PCWU.GATE_CD, PCWU.WORKER_USER_ID, #{ses.langCd}) AS WORKER_NM ,USERD.EMAIL AS EMAIL ,USERD.TEL_NUM AS TEL_NUM ,USERD.CELL_NUM AS CELL_NUM , PCCT.CONT_USER_ID ,GETUSERNAME(PCCT.GATE_CD, PCCT.CONT_USER_ID, #{ses.langCd}) AS CONT_USER_NM ,USERC.TEL_NUM AS CONT_TEL_NUM , USERD.SITE_USER_ID ,getUserName(USERD.GATE_CD, USERD.SITE_USER_ID, #{ses.langCd}) AS SITE_USER_NM ,GETCODENAME(USERD.GATE_CD, 'M151', USERD.GENDER, #{ses.langCd}) AS GENDER ,USERC.ZIP_CD AS ZIP_CD ,USERD.ADDR_1 AS ADDR_1 ,USERD.ADDR_2 AS ADDR_2 ,(USERD.BIRTH_DATE, 'yyyyMMdd') AS BIRTH_DATE , PCWU.WORKER_DEPT_NM , PCWU.WORKER_JOB_NM ,(PCWU.WORKER_CONT_DATE, 'yyyyMMdd') AS WORKER_CONT_DATE ,(PCWU.WORKER_CONT_START_DATE, 'yyyyMMdd') AS WORKER_CONT_START_DATE ,(PCWU.WORKER_CONT_END_DATE, 'yyyyMMdd') AS WORKER_CONT_END_DATE , PCWU.WORKER_CONT_TYPE , PCWU.WORKER_PAY_AMT , PCWU.BASE_PAY , PCWU.BASE_PAY_RMKS , PCWU.FOOD_PAY , PCWU.FOOD_PAY_RMKS , PCWU.JOB_PAY , PCWU.JOB_PAY_RMKS , PCWU.EXTEND_PAY , PCWU.EXTEND_PAY_RMKS , PCWU.WORK_PAY , PCWU.WORK_PAY_RMKS , PCWU.NIGHT_PAY , PCWU.NIGHT_PAY_RMKS , PCWU.ETC_PAY , PCWU.ETC_PAY_RMKS , PCWU.ETC_PAY2 , PCWU.ETC_PAY2_RMKS , PCWU.ETC_PAY3 , PCWU.ETC_PAY3_RMKS , PCWU.SPEC_RMKS , PCCT.ATT_FILE_NUM ,((PCWU.SIGN_DATE, 'YYYY-MM-DD HH24:MI'),' ') AS SIGN_DATE ,getFileCount(PCCT.GATE_CD, PCCT.ATT_FILE_NUM) AS ATT_FILE_CNT , PCWU.WORKER_USER_ID AS ENC_WORKER_ID FROM STOCPCCT PCCT JOIN STOCPCWU PCWU ON( PCCT.GATE_CD = PCWU.GATE_CD AND PCCT.BUYER_CD = PCWU.BUYER_CD AND PCCT.CONT_NUM = PCWU.CONT_NUM AND PCCT.CONT_CNT = PCWU.CONT_CNT AND PCWU.DEL_FLAG = '0') LEFT OUTER JOIN STOCCVUR USERC ON( PCCT.GATE_CD = USERC.GATE_CD AND PCCT.CONT_USER_ID = USERC.USER_ID AND USERC.DEL_FLAG = '0') LEFT OUTER JOIN STOCCVUR USERD ON( PCWU.GATE_CD = USERD.GATE_CD AND PCWU.WORKER_USER_ID = USERD.USER_ID AND USERD.DEL_FLAG = '0') WHERE 1 = 1 AND PCCT.GATE_CD = #{ses.gateCd} AND PCCT.BUYER_CD = #{BUYER_CD}
AND PCCT.CONT_NUM = #{CONT_NUM} AND PCCT.CONT_CNT = #{CONT_CNT}
AND PCCT.APP_DOC_NUM = #{APP_DOC_NUM} AND PCCT.APP_DOC_CNT = #{APP_DOC_CNT}
AND PCCT.DEL_FLAG = '0'

mapper.update:
UPDATE STOCPCWU
   SET MOD_DATE     = ${systemDateTime}
     , MOD_USER_ID  = #{ses.userId}
     , SEND_YN = #{SEND_YN}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND WORKER_USER_ID = #{ENC_WORKER_ID}

UPDATE STOCPCCT
   SET MOD_DATE     = ${systemDateTime}
     , MOD_USER_ID  = #{ses.userId}
     , CONT_USER_ID = #{CHANGE_CONT_USER_ID}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}

UPDATE STOCCVUR USR
   SET MOD_DATE     = ${systemDateTime}
     , MOD_USER_ID  = #{ses.userId}
     , SITE_USER_ID = #{CHANGE_CONT_USER_ID}
 WHERE USR.GATE_CD  = #{ses.gateCd}
   AND EXISTS (SELECT 1 FROM STOCPCWU
                WHERE GATE_CD  = USR.GATE_CD
                  AND BUYER_CD = #{BUYER_CD}
                  AND CONT_NUM = #{CONT_NUM}
                  AND CONT_CNT = #{CONT_CNT}
                  AND WORKER_USER_ID = USR.USER_ID
                  AND DEL_FLAG = '0')

mapper.select:
SELECT X.* ,(CASE WHEN X.CONT_QTY > 1 THEN X.CONT_NUM || '외 ' || X.CONT_QTY || '건' ELSE X.CONT_NUM END) AS CONT_INFO FROM ( SELECT CVUR.USER_ID ,CVUR.USER_NM AS USER_NM ,(CVUR.REG_DATE, 'yyyyMMdd') AS REQ_DATE , CVUR.POSITION_NM , CVUR.DUTY_NM , CVUR.EMPLOYEE_NO ,CVUR.EMAIL AS EMAIL ,CVUR.TEL_NUM AS TEL_NUM ,CVUR.CELL_NUM AS CELL_NUM , CVUR.PROGRESS_CD , CVUR.AGREE_YN ,(CVUR.AGREE_YN_DATE, 'yyyyMMdd') AS AGREE_DATE , CVUR.SITE_USER_ID ,getUserName(CVUR.GATE_CD, CVUR.SITE_USER_ID, #{ses.langCd}) AS SITE_USER_NM , CVUR.GENDER ,GETCODENAME(CVUR.GATE_CD, 'M151', CVUR.GENDER, #{ses.langCd}) AS GENDER_NM ,CVUR.ZIP_CD AS ZIP_CD ,CVUR.ADDR_1 AS ADDR_1 ,CVUR.ADDR_2 AS ADDR_2 ,(CVUR.BIRTH_DATE, 'yyyyMMdd') AS BIRTH_DATE ,((CVUR.CONFIRM_DATE, 'YYYY-MM-DD HH24:MI'),' ') AS SIGN_DATE , CVUR.CONFIRM_USER_ID AS SIGN_USER_ID ,getUserName(CVUR.GATE_CD, CVUR.CONFIRM_USER_ID, #{ses.langCd}) AS SIGN_USER_NM ,(SELECT MAX(PCCT.CONT_NUM) FROM STOCPCWU PCWU JOIN STOCPCCT PCCT ON (PCWU.GATE_CD = PCCT.GATE_CD AND PCWU.CONT_NUM = PCCT.CONT_NUM AND PCWU.CONT_CNT = PCCT.CONT_CNT AND PCCT.SIGN_STATUS IN ('T','P','E') -- 작성중, 결재중, 승인 (상신취소, 결재반려 제외) AND PCCT.DEL_FLAG = '0') WHERE PCWU.GATE_CD = CVUR.GATE_CD AND PCWU.WORKER_USER_ID = CVUR.USER_ID AND ((PCWU.WORKER_CONT_END_DATE, 'YYYYMMDD'),' ') >= (SYSDATE, 'YYYYMMDD') -- 계약종료일자 >= 현재일자 AND PCWU.PROGRESS_CD IN ('100','200') -- 서명대기, 서명완료 (서명중단 제외) AND PCWU.DEL_FLAG = '0') AS CONT_NUM ,(SELECT COUNT(PCCT.CONT_NUM) FROM STOCPCWU PCWU JOIN STOCPCCT PCCT ON (PCWU.GATE_CD = PCCT.GATE_CD AND PCWU.CONT_NUM = PCCT.CONT_NUM AND PCWU.CONT_CNT = PCCT.CONT_CNT AND PCCT.SIGN_STATUS IN ('T','P','E') -- 작성중, 결재중, 승인 (상신취소, 결재반려 제외) AND PCCT.DEL_FLAG = '0') WHERE PCWU.GATE_CD = CVUR.GATE_CD AND PCWU.WORKER_USER_ID = CVUR.USER_ID AND ((PCWU.WORKER_CONT_END_DATE, 'YYYYMMDD'),' ') >= (SYSDATE, 'YYYYMMDD') -- 계약종료일자 >= 현재일자 AND PCWU.PROGRESS_CD IN ('100','200') -- 서명대기, 서명완료 (서명중단 제외) AND PCWU.DEL_FLAG = '0') AS CONT_QTY ,(CASE WHEN CVUR.PROGRESS_CD = 'P' THEN '1' WHEN CVUR.PROGRESS_CD = 'R' THEN '2' ELSE '3' END) AS SORT_ORD ,GETCODENAME(CVUR.GATE_CD, 'M044', CVUR.DEL_FLAG, #{ses.langCd}) AS USER_DEL_FLAG FROM STOCCVUR CVUR WHERE CVUR.GATE_CD = #{ses.gateCd} AND CVUR.USER_TYPE = 'P'
AND CVUR.SITE_USER_ID = #{ses.userId}
AND CVUR.REG_DATE >= (#{REQ_FROM_DATE}) AND CVUR.REG_DATE <= (#{REQ_TO_DATE})
AND CVUR.USER_ID = #{USER_ID}
AND UPPER(GETUSERNAME(CVUR.GATE_CD, CVUR.USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{USER_NM}) '%'
AND CVUR.PROGRESS_CD = #{PROGRESS_CD}
AND UPPER(GETUSERNAME(CVUR.GATE_CD, CVUR.SITE_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{SITE_USER_NM}) '%'
AND CVUR.CELL_NUM LIKE '%' #{CELL_NUM} '%'
) X WHERE 1 = 1 ORDER BY X.SORT_ORD , X.AGREE_DATE , X.USER_NM

mapper.update:
UPDATE STOCCVUR USR
   SET MOD_DATE    = SYSDATE
     , MOD_USER_ID = #{ses.userId}
     , PROGRESS_CD = #{PROGRESS_CD}

     , CONFIRM_DATE    = SYSDATE
     , CONFIRM_USER_ID = #{ses.userId}

 WHERE USR.GATE_CD   = #{ses.gateCd}
   AND USR.USER_ID   = #{USER_ID}
   AND USR.USER_TYPE = 'P'
